const bin = $binary?.data || $binary?.file || Object.values($binary || {})[0] || null;
if (!bin) throw new Error('No file binary found. Send multipart/form-data with field "data".');
const token = $json.body?.googleAccessToken || $json.googleAccessToken || '';
return { json: { ...$json, _uploadToken: token }, binary: { data: bin } };

const items = $input.all();
if (!items.length) return [];
const token = $('Normalize Upload').first().json._uploadToken || '';
const keys = Object.keys(items[0].json);
const find = (re) => keys.find(k => re.test(k)) || '';
const dLinkKey = find(/drive.*link|invoice.*link|invoice.*url|link|url|drive|invoice|file/i);
const payeeKey = find(/payee|beneficiary|account[_\s-]?name|acc[_\s-]?name/i);
const acctKey  = find(/account[_\s-]?no|acct|a\/c|bank[_\s-]?acc|acc.*no/i);
const ifscKey  = find(/ifsc/i);
const amountKey = find(/amount|total|value|sum|invoice.*amount/i);
return items.map((item, idx) => ({
  json: {
    ...item.json,
    _idx:          idx,
    _token:        token,
    _driveLink:    dLinkKey ? String(item.json[dLinkKey] || '').trim() : '',
    _payee:        payeeKey ? String(item.json[payeeKey] || '').trim() : '',
    _acct:         acctKey  ? String(item.json[acctKey]  || '').trim() : '',
    _ifsc:         ifscKey  ? String(item.json[ifscKey]  || '').trim() : '',
    _amount:       amountKey ? String(item.json[amountKey] || '').trim() : '',
    _payeeKey:     payeeKey,
    _acctKey:      acctKey,
    _ifscKey:      ifscKey,
    _amountKey:    amountKey,
    _dLinkKey:     dLinkKey,
    _originalKeys: keys,
    _status:       '',
  },
}));

const link = $json._driveLink || '';
const m1 = link.match(/\/d\/([a-zA-Z0-9_-]+)/);
const m2 = link.match(/[?&]id=([a-zA-Z0-9_-]+)/);
const fileId = (m1 && m1[1]) || (m2 && m2[1]) || '';
if (!fileId) return { json: { ...$json, _status: 'Error: could not parse Drive file ID', _fileId: '' } };
return { json: { ...$json, _fileId: fileId } };

const meta = $json;
const row = $('Parse Drive File ID').item.json;

if (row._status && row._status.startsWith('Error')) {
  return { json: { ...row, _fileClass: 'error' } };
}

if (meta.error) {
  const code = meta.error.code || 0;
  const status =
    code === 401
      ? 'Error: Google session expired — sign out and sign in again'
      : 'Error: Drive file not accessible (check permissions)';
  return {
    json: { ...row, _mimeType: '', _fileName: '', _fileClass: 'error', _status: status, _downloadUrl: '' },
  };
}

const mime = meta.mimeType || '';
const fileId = row._fileId || '';
let fileClass = 'document';
let status = '';
let exportAsPdf = false;

if (mime.startsWith('image/')) {
  fileClass = 'image';
} else if (mime.startsWith('application/vnd.google-apps.')) {
  fileClass = 'document';
  exportAsPdf = true;
} else if (!mime) {
  fileClass = 'error';
  status = 'Error: Drive file not accessible (check permissions)';
} else {
  // PDF and other binary formats — download directly. DOC/DOCX are downloaded then
  // converted to PDF in Restore Row After Download before Gemini Analyze Document.
  fileClass = 'document';
}

let downloadUrl = '';
if (fileId && fileClass !== 'error') {
  downloadUrl = exportAsPdf
    ? `https://www.googleapis.com/drive/v3/files/${fileId}/export?mimeType=application%2Fpdf`
    : `https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`;
}

return {
  json: {
    ...row,
    _mimeType: mime,
    _fileName: meta.name || '',
    _fileClass: fileClass,
    _status: status,
    _downloadUrl: downloadUrl,
  },
};

const row = $('Classify MimeType').item.json;
const binData = $binary?.invoiceFile || null;

if (!binData) {
  return {
    json: {
      ...row,
      _status: 'Error: file download failed (check Drive permissions)',
      _downloadFailed: true,
    },
  };
}

const OFFICE_DOC_MIMES = new Set([
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
]);

const mime = row._mimeType || '';
const fileId = row._fileId || row.fileId || '';
const token = row._token || row.token || '';

if (!OFFICE_DOC_MIMES.has(mime)) {
  return { json: { ...row, _downloadFailed: false }, binary: { invoiceFile: binData } };
}

if (!fileId || !token) {
  return {
    json: {
      ...row,
      _status: 'Error: missing Drive file ID or token for DOC/DOCX conversion',
      _downloadFailed: true,
    },
  };
}

let copyId = '';
try {
  const copy = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://www.googleapis.com/drive/v3/files/${fileId}/copy`,
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: {
      mimeType: 'application/vnd.google-apps.document',
      name: `__ledgerlens_convert_${fileId}`,
    },
    json: true,
  });
  copyId = copy.id;

  const pdfBuffer = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://www.googleapis.com/drive/v3/files/${copyId}/export?mimeType=application/pdf`,
    headers: { Authorization: `Bearer ${token}` },
    encoding: 'arraybuffer',
  });

  const pdfName = (row._fileName || 'invoice').replace(/\.[^.]+$/i, '') + '.pdf';
  const pdfBinary = await this.helpers.prepareBinaryData(pdfBuffer, pdfName, 'application/pdf');

  return {
    json: {
      ...row,
      _downloadFailed: false,
      _geminiMimeType: 'application/pdf',
      _convertedFromOffice: true,
    },
    binary: { invoiceFile: pdfBinary },
  };
} catch (e) {
  const msg = String(e.message || e);
  const needsReauth = /403|insufficient|permission|scope/i.test(msg);
  return {
    json: {
      ...row,
      _status: needsReauth
        ? 'Error: DOC/DOCX conversion needs Drive access — sign out and sign in again'
        : 'Error: could not convert DOC/DOCX to PDF — ' + msg,
      _downloadFailed: true,
    },
  };
} finally {
  if (copyId && token) {
    try {
      await this.helpers.httpRequest({
        method: 'DELETE',
        url: `https://www.googleapis.com/drive/v3/files/${copyId}`,
        headers: { Authorization: `Bearer ${token}` },
      });
    } catch (_) {
      // Best-effort cleanup of temporary Google Doc copy
    }
  }
}

const OPENROUTER_MODEL = 'nvidia/nemotron-nano-12b-v2-vl:free';

const EXTRACTION_PROMPT = `You are reading an invoice document. Extract ONLY these four fields and return valid JSON with no prose, no markdown, no code fences:

{"payee":"string","account_number":"string","ifsc":"string","amount":"string","confidence":0.0}

Rules:
- payee: the account payee or beneficiary name exactly as printed
- account_number: digits only, no spaces or dashes
- ifsc: exactly 11 characters, uppercase (e.g. HDFC0001234)
- amount: invoice total or grand total as printed (digits and decimal point only, no currency symbols or commas). Always include this field when visible on the invoice.
- confidence: 0.0 to 1.0
- If a field is missing or unreadable, use "" and lower confidence`;

const bin = $binary?.invoiceFile || null;
if (!bin) {
  return { json: { error: 'No invoice file binary found for OpenRouter analysis' } };
}

const buffer = await this.helpers.getBinaryDataBuffer(0, 'invoiceFile');
const base64 = Buffer.from(buffer).toString('base64');

let mime = $('Restore Row After Download').item.json._geminiMimeType
  || $('Restore Row After Download').item.json._mimeType
  || bin.mimeType
  || 'application/octet-stream';

if (mime === 'application/octet-stream' && $('Restore Row After Download').item.json._fileClass === 'image') {
  mime = 'image/jpeg';
}
if (mime !== 'application/pdf' && !mime.startsWith('image/')) {
  if ($('Restore Row After Download').item.json._fileClass === 'document') {
    mime = 'application/pdf';
  }
}

const dataUrl = `data:${mime};base64,${base64}`;

function buildVisionContent(prompt) {
  if (mime === 'application/pdf') {
    return [
      {
        type: 'file',
        file: {
          filename: 'invoice.pdf',
          file_data: dataUrl,
        },
      },
      { type: 'text', text: prompt },
    ];
  }

  return [
    {
      type: 'image_url',
      image_url: { url: dataUrl },
    },
    { type: 'text', text: prompt },
  ];
}

const _openRouterBody = {
  model: OPENROUTER_MODEL,
  max_tokens: 1024,
  messages: [
    {
      role: 'user',
      content: buildVisionContent(EXTRACTION_PROMPT),
    },
  ],
};
return {
  json: {
    _openRouterBody,
    _openRouterModel: OPENROUTER_MODEL,
  },
};

const row = $('Restore Row After Download').item.json;
if (row._downloadFailed) return { json: row };

function formatError(err) {
  if (err == null || err === '') return 'unknown error';
  if (typeof err === 'string') return err;
  return err.message || JSON.stringify(err);
}

function getPrepareError() {
  for (const name of ['OpenRouter Analyze Image', 'OpenRouter Analyze Document']) {
    try {
      const prep = $(name).first()?.json;
      if (prep?.error) return formatError(prep.error);
    } catch (_) {}
  }
  return '';
}

const prepareError = getPrepareError();
if (prepareError) {
  return { json: { ...row, _status: 'Error: extraction analyze failed - ' + prepareError } };
}

if ($json.error) {
  return { json: { ...row, _status: 'Error: extraction analyze failed - ' + formatError($json.error) } };
}

function extractRawModelText(data) {
  if (!data) return '';
  if (typeof data.text === 'string') return data.text;
  if (typeof data.output === 'string') return data.output;
  if (typeof data.content === 'string') return data.content;
  const openAiContent = data.choices?.[0]?.message?.content;
  if (typeof openAiContent === 'string') return openAiContent;
  const openAiText = data.choices?.[0]?.text;
  if (typeof openAiText === 'string') return openAiText;
  const messageContent = data.message?.content;
  if (typeof messageContent === 'string') return messageContent;
  const partText = data.content?.parts?.[0]?.text;
  if (typeof partText === 'string') return partText;
  return '';
}

function normalizeAmount(val) {
  const s = String(val ?? '').trim();
  if (!s) return '';
  return s.replace(/[^\d.]/g, '');
}

function parseExtractionPayload(data) {
  if (
    data.payee !== undefined ||
    data.account_number !== undefined ||
    data.ifsc !== undefined ||
    data.amount !== undefined ||
    data.total !== undefined
  ) {
    return data;
  }
  const raw = extractRawModelText(data);
  if (!raw) return null;
  const cleaned = raw.replace(/```json?\n?/gi, '').replace(/```/g, '').trim();
  return JSON.parse(cleaned);
}

try {
  const p = parseExtractionPayload($json);
  if (!p) {
    return { json: { ...row, _status: 'Error: model returned empty extraction' } };
  }

  if (p.error) {
    return { json: { ...row, _status: 'Error: extraction analyze failed - ' + p.error } };
  }

  const payee = String(p.payee || '').trim();
  const acct = String(p.account_number || p.bank_number || p.bank_account_number || '')
    .replace(/\D/g, '');
  const ifsc = String(p.ifsc || '').toUpperCase().trim();
  const amount = normalizeAmount(
    p.amount ?? p.total ?? p.total_amount ?? p.invoice_amount ?? p.invoice_total
  );
  const confidence = typeof p.confidence === 'number' ? p.confidence : 0;

  const _parseSource = extractRawModelText($json) ? 'model-text' : 'top-level';

  if (!payee && !acct && !ifsc && !amount) {
    return {
      json: {
        ...row,
        _status: 'Error: model returned empty extraction',
        _confidence: confidence,
        _parseSource,
      },
    };
  }

  return {
    json: {
      ...row,
      _extractedPayee: payee,
      _extractedAcct: acct,
      _extractedIfsc: ifsc,
      _extractedAmount: amount,
      _confidence: confidence,
      _status: 'Done',
      _parseSource,
    },
  };
} catch (e) {
  return { json: { ...row, _status: 'Error: model response not parseable - ' + e.message } };
}

